class Solution:
    def countConsistentStrings(self, allowed, words):
        mask = 0
        for c in allowed:
            mask |= 1 << (ord(c) - ord('a'))
        count = 0
        for w in words:
            wmask = 0
            for c in w:
                wmask |= 1 << (ord(c) - ord('a'))
            if wmask & ~mask == 0:
                count += 1
        return count

