var countConsistentStrings = function(allowed, words) {
    const allowedSet = new Set(allowed.split(''));
    let count = 0;
    for (const w of words) {
        let ok = true;
        for (const c of w) {
            if (!allowedSet.has(c)) { ok = false; break; }
        }
        if (ok) count++;
    }
    return count;
};
